import React, { useState, useEffect } from 'react';
import axios from 'axios';

function ClientDashboard() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchAllProjects = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/requests');
        setProjects(res.data);
        setLoading(false);
      } catch (err) {
        console.error("Error fetching data:", err);
        setLoading(false);
      }
    };
    fetchAllProjects();
  }, []);

  if (loading) return <div className="text-center py-5">Loading Live Dashboard...</div>;

  return (
    <div className="dashboard-wrapper py-5 min-vh-100" style={{ backgroundColor: '#f4f7fa' }}>
      <div className="container">
        
        {/* Header Section */}
        <div className="text-center mb-5 animate__animated animate__fadeInDown">
          <h2 className="display-4 fw-bold text-dark mb-2">Project <span className="text-primary">Pulse</span></h2>
          <p className="text-muted fs-5">Live tracking for all active client projects</p>
          <div className="mx-auto bg-primary rounded-pill mt-2" style={{ width: '60px', height: '5px' }}></div>
        </div>
        
        <div className="row g-4 justify-content-center">
          {projects.map((project) => {
            const remaining = project.totalBudget - project.advancePaid;
            
            return (
              <div key={project._id} className="col-lg-10">
                <div className="glass-card border-0 rounded-4 overflow-hidden mb-4 shadow-sm animate__animated animate__fadeInUp">
                  
                  {/* Card Header: Client & Status */}
                  <div className="p-4 d-flex justify-content-between align-items-center bg-white border-bottom">
                    <div className="client-meta">
                      <h3 className="fw-bold mb-1 text-dark text-capitalize">{project.fullName}</h3>
                      <span className="badge bg-primary-soft text-primary px-3 py-2 rounded-pill fw-bold" style={{ fontSize: '0.75rem' }}>
                        <i className="fas fa-rocket me-2"></i>{project.serviceType}
                      </span>
                    </div>
                    
                    {/* CORRECTED PAYMENT BADGE LOGIC */}
                    <div className="payment-status">
                      {remaining <= 0 ? (
                        <span className="badge-premium paid">
                          <i className="fas fa-check-circle me-2"></i>FULLY PAID
                        </span>
                      ) : (
                        <span className="badge-premium pending">
                          <i className="fas fa-clock me-2"></i>PAYMENT PENDING
                        </span>
                      )}
                    </div>
                  </div>
                  
                  {/* Card Body: Progress Bar */}
                  <div className="card-body p-4 p-lg-5 bg-white">
                    <div className="progress-container mb-5">
                      <div className="d-flex justify-content-between mb-3 align-items-end">
                        <h6 className="fw-bold text-muted text-uppercase mb-0" style={{ letterSpacing: '1px', fontSize: '0.8rem' }}>Development Phase</h6>
                        <span className="fw-bold text-primary display-6" style={{ fontSize: '1.8rem' }}>{project.progress}%</span>
                      </div>
                      <div className="progress custom-bar shadow-sm" style={{ height: '14px' }}>
                        <div 
                          className={`progress-bar progress-bar-striped progress-bar-animated ${project.progress === 100 ? 'bg-success' : 'bg-primary'}`} 
                          style={{ width: `${project.progress}%` }}
                        ></div>
                      </div>
                    </div>

                    {/* Stats Grid: Budget, Received, Remaining */}
                    <div className="row g-0 rounded-4 overflow-hidden border">
                      <div className="col-md-4 stat-item">
                        <small className="text-muted fw-bold d-block text-uppercase mb-2">Total Budget</small>
                        <h4 className="fw-bold mb-0 text-dark">₹{project.totalBudget}</h4>
                      </div>
                      <div className="col-md-4 stat-item border-start border-end bg-light-soft">
                        <small className="text-muted fw-bold d-block text-uppercase mb-2">Advance Received</small>
                        <h4 className="fw-bold mb-0 text-success">₹{project.advancePaid}</h4>
                      </div>
                      <div className="col-md-4 stat-item">
                        <small className="text-muted fw-bold d-block text-uppercase mb-2">Remaining Dues</small>
                        <h4 className={`fw-bold mb-0 ${remaining > 0 ? 'text-danger' : 'text-success'}`}>
                          ₹{remaining}
                        </h4>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}

          {projects.length === 0 && (
            <div className="text-center py-5">
              <i className="fas fa-folder-open fa-3x text-muted mb-3"></i>
              <h4 className="text-muted">No active projects to track.</h4>
            </div>
          )}
        </div>
      </div>

      {/* --- PREMIUM INTERNAL CSS --- */}
      <style>{`
        .glass-card { transition: transform 0.3s ease, box-shadow 0.3s ease; border: 1px solid #e1e8f0; }
        .glass-card:hover { transform: translateY(-8px); box-shadow: 0 20px 40px rgba(0,0,0,0.08) !important; }
        
        .bg-primary-soft { background-color: #eef4ff; }
        .bg-light-soft { background-color: #fafbfc; }
        
        .badge-premium { padding: 10px 20px; border-radius: 50px; font-weight: 800; font-size: 0.75rem; letter-spacing: 0.5px; display: inline-flex; align-items: center; }
        .badge-premium.paid { background-color: #d1e7dd; color: #0f5132; border: 1px solid #badbcc; }
        .badge-premium.pending { background-color: #fff3cd; color: #856404; border: 1px solid #ffeeba; }
        
        .custom-bar { border-radius: 50px; background-color: #edf2f7; }
        .stat-item { padding: 30px 15px; text-align: center; }
        
        @media (max-width: 768px) {
          .stat-item { border: none !important; border-bottom: 1px solid #eee !important; }
          .stat-item:last-child { border-bottom: none !important; }
        }
      `}</style>
    </div>
  );
}

export default ClientDashboard;
